#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int max1=-1, max2=-1;
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            if(x>max1){
                max2=max1;
                max1=x;
            }else if(x!=max1 && x>max2){
                max2=x;
            }
        }
        printf("%d\n", max1+max2);
    }
    return 0;
}

