#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        max1 = -1
        max2 = -1
        for _ in range(N):
            x = int(next(it))
            if x > max1:
                max2 = max1
                max1 = x
            elif x != max1 and x > max2:
                max2 = x
        out.append(str(max1 + max2))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

